// This file is generated by AI.

import { useEffect, useMemo, useState } from 'react';
import { SceneEditor } from './Editor';
import { Output } from './Output';
import { loadWasm, type WasmModule } from './wasm';

const defaultText = '';

interface LineRange {
  startLine: number;
  endLine: number;
}

function buildLineRanges(data: unknown): Array<{ startLine: number; endLine: number }> {
  if (!Array.isArray(data)) {
    return [];
  }

  const json = JSON.stringify(data, null, 2);
  const lines = json.split('\n');
  const ranges: Array<{ startLine: number; endLine: number }> = [];
  let index = 0;

  while (index < lines.length) {
    const line = lines[index];
    const indent = line.match(/^\s*/)?.[0].length ?? 0;

    if (indent === 2 && /^\s*\{$/.test(line)) {
      let depth = 0;
      let endLine = index;

      for (let cursor = index; cursor < lines.length; cursor += 1) {
        const currentLine = lines[cursor];
        depth += (currentLine.match(/\{/g) ?? []).length;
        depth -= (currentLine.match(/\}/g) ?? []).length;
        if (depth === 0) {
          endLine = cursor;
          break;
        }
      }

      ranges.push({ startLine: index, endLine });
      index = endLine + 1;
      continue;
    }

    index += 1;
  }

  return ranges;
}

function buildSentenceLineMap(text: string): number[] {
  return text.split('\n').reduce<number[]>((lines, currentLine, index) => {
    if (currentLine.trim().length > 0) {
      lines.push(index);
    }
    return lines;
  }, []);
}

export function App() {
  const [text, setText] = useState(defaultText);
  const [data, setData] = useState<unknown>(null);
  const [error, setError] = useState<string | null>(null);
  const [wasm, setWasm] = useState<WasmModule | null>(null);
  const [isSyncEnabled, setIsSyncEnabled] = useState(false);
  const [elapsedMs, setElapsedMs] = useState<string>('--');
  const [cursorLine, setCursorLine] = useState<number | null>(null);
  const [lineRange, setLineRange] = useState<LineRange | null>(null);
  const [lineRanges, setLineRanges] = useState<Array<LineRange>>([]);

  useEffect(() => {
    let active = true;

    fetch('./example.txt')
      .then((response) => {
        if (!response.ok) {
          throw new Error(`Failed to load example script: ${response.status}`);
        }
        return response.text();
      })
      .then((content) => {
        if (active) {
          setText(content || defaultText);
        }
      })
      .catch(() => {
        if (active) {
          setText(defaultText);
        }
      });

    loadWasm()
      .then((module) => {
        if (active) {
          setWasm(module);
        }
      })
      .catch((err) => {
        if (active) {
          setError(err instanceof Error ? err.message : String(err));
        }
      });

    return () => {
      active = false;
    };
  }, []);

  useEffect(() => {
    if (!wasm) return;

    wasm.updateScene(text);
    const parseTime = wasm.getLastParseTime();
    if (parseTime !== null) {
      setElapsedMs(`${parseTime.toFixed(1)} ms`);
    }

    const timer = window.setTimeout(() => {
      try {
        const sentences = wasm.getSentences();
        setData(sentences);
        setLineRanges(buildLineRanges(sentences));
        setError(null);
      } catch (err) {
        const message = err instanceof Error ? err.message : String(err);
        setError(message);
        setData(null);
        setLineRanges([]);
      }
    }, 300);

    return () => window.clearTimeout(timer);
  }, [text, wasm]);

  useEffect(() => {
    if (!isSyncEnabled || cursorLine === null || lineRanges.length === 0) {
      setLineRange(null);
      return;
    }

    const sentenceLineMap = buildSentenceLineMap(text);
    if (sentenceLineMap.length === 0) {
      setLineRange(null);
      return;
    }

    let sentenceIndex = -1;
    for (let index = 0; index < sentenceLineMap.length; index += 1) {
      if (sentenceLineMap[index] <= cursorLine) {
        sentenceIndex = index;
      } else {
        break;
      }
    }

    const targetIndex = sentenceIndex === -1 ? 0 : Math.min(sentenceIndex, lineRanges.length - 1);
    setLineRange(lineRanges[targetIndex]);
  }, [cursorLine, lineRanges, isSyncEnabled, text]);

  const layoutStyle = useMemo<React.CSSProperties>(
    () => ({
      display: 'flex',
      flexDirection: 'column',
      height: '100%',
      width: '100%',
      overflow: 'hidden',
      background: '#252526',
      color: '#f5f5f5',
    }),
    []
  );

  return (
    <div style={layoutStyle}>
      <div style={{ height: '48px', background: '#2d2d30', borderBottom: '1px solid #3c3c3c', display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 1rem' }}>
        <div style={{ fontWeight: 700 }}>WebGAL Parse Playground</div>
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
          <button onClick={() => setIsSyncEnabled((value) => !value)} style={{ border: '1px solid #3c3c3c', background: isSyncEnabled ? '#0e639c' : '#3c3c3c', color: '#f5f5f5', padding: '0.35rem 0.75rem', borderRadius: '4px', cursor: 'pointer' }}>
            {isSyncEnabled ? '同步：开' : '同步：关'}
          </button>
          <div style={{ color: '#d4d4d4' }}>耗时：{elapsedMs}</div>
        </div>
      </div>
      <div style={{ display: 'flex', flex: 1, minHeight: 0, minWidth: 0 }}>
        <div style={{ flex: 1, minHeight: 0, minWidth: 0, borderRight: '1px solid #3c3c3c' }}>
          <SceneEditor value={text} onChange={setText} onCursorChange={isSyncEnabled ? setCursorLine : undefined} wasm={wasm} />
        </div>
        <div style={{ flex: 1, minHeight: 0, minWidth: 0 }}>
          <Output data={data} error={error} lineRange={lineRange} />
        </div>
      </div>
    </div>
  );
}
